 25→} from './utils/cosmicPhysics';
 26→import { computeConstellationChains, assignChainColors } from './utils/constellationUtils';
 27→import { handleClickProfile } from '../../../helpers/handleClicks';
 28→import styles from './Universe.module.css';
 29→
 30→const SECTOR_SIZE = 2000;
 31→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 32→
 33→const Universe = () => {
 34→    const navigate = useNavigate();
 35→    const location = useLocation();
 36→    const { user, session } = useAuth();
 37→    const userId = user?.userData?.[0]?.id || null;
 38→
 39→    const fetchDebounceRef = useRef(null);
 40→    const settleDebounceRef = useRef(null);
 41→    const lastSettledPayloadRef = useRef('');
 42→    const initialFetchResolvedRef = useRef(false);
 43→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 44→    const ownGalaxyLookupStartedRef = useRef(false);
 45→    const constellationFlyToRef = useRef(location.state?.flyToConstellation || null);
 46→
 47→    const [posts, setPosts] = useState(new Map());
 48→    const [selectedPost, setSelectedPost] = useState(null);
 49→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 50→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 51→    const [pulsingId, setPulsingId] = useState(null);
 52→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 53→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 54→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 55→    const [wormholes, setWormholes] = useState([]);
 56→    const [isWarping, setIsWarping] = useState(false);
 57→    const [constellations, setConstellations] = useState([]);
 58→    const [linkModeError, setLinkModeError] = useState(null);
 59→
 60→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 61→    const [centroids, setCentroids] = useState([]);
 62→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 63→    const [similarPairs, setSimilarPairs] = useState([]);
 64→    const [starPulls, setStarPulls] = useState([]);
 65→
 66→    // Shared ref: prevents camera pan while dragging a star
 67→    const isStarDragging = useRef(false);
 68→
 69→    const {
 70→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 71→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 72→    } = useUniverseCamera(userId, hasOwnPosts, isStarDragging);
 73→
 74→    const {
 75→        isLinkMode, firstStar, isSubmitting, linkModeStatus,
 76→        toggleLinkMode, cancelLinkMode, handleStarClickInLinkMode,
 77→    } = useConstellationLinkMode(userId, session);
 78→
 79→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 80→    const showTitles = zoom > 0.5;
 81→
 82→    // Sector partitioning for scalable local gravity math.
 83→    const postSectorIndex = useMemo(() => (
 84→        buildSectorIndex(
 85→            postArray,
 86→            (post) => ({
 87→                x: post?.display_x ?? post?.universe_x,
 88→                y: post?.display_y ?? post?.universe_y,
 89→            }),
 90→            SECTOR_SIZE
 91→        )
 92→    ), [postArray]);
 93→
 94→    const centerSectorKey = useMemo(
 95→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 96→        [centerWorld.x, centerWorld.y]
 97→    );
 98→
 99→    const activeSectorKeys = useMemo(
100→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
101→        [centerSectorKey]
102→    );
103→
104→    const activePosts = useMemo(() => {
105→        if (activeSectorKeys.size === 0) return postArray;
106→
107→        const next = [];
108→        for (const key of activeSectorKeys) {
109→            const bucket = postSectorIndex.get(key);
110→            if (bucket?.length) next.push(...bucket);
111→        }
112→        return next;
113→    }, [postArray, postSectorIndex, activeSectorKeys]);
114→
115→    const activePostIds = useMemo(() => {
116→        const ids = new Set();
117→        for (const post of activePosts) {
118→            if (post?.id) ids.add(post.id);
119→        }
120→        return ids;
121→    }, [activePosts]);
122→
123→    const { centroidByUser } = useMemo(
124→        () => computeGalaxyCentroids(postArray),
125→        [postArray]
126→    );
127→
128→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
129→    const hashGalaxies = useMemo(() => {
130→        const seen = new Map();
131→        for (const post of postArray) {
132→            const uid = post.users?.id ?? post.user_id;
133→            if (!uid || seen.has(uid)) continue;
134→            const hash = userHomeCoords(uid);
135→            seen.set(uid, {
136→                userId: uid,
137→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
138→                x: hash.x,
139→                y: hash.y,
140→            });
141→        }
142→        return Array.from(seen.values());
143→    }, [postArray]);
144→
145→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
146→    const centroidTargets = useMemo(() => {
147→        const map = new Map();
148→        for (const c of centroids) {
149→            if (c.galaxy_x != null && c.galaxy_y != null) {
150→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
151→            }
152→        }
153→        return map;
154→    }, [centroids]);
155→
156→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
157→    const {
158→        galaxyPositions,
159→        starPullOffsets,
160→        isSettled,
161→        galaxyEdges: effectiveGalaxyEdges,
162→        hasEmbeddingGravity,
163→    } = useCosmicGravity({
164→        galaxies: hashGalaxies,
165→        centroidTargets,
166→        edges: galaxyEdges,
167→        posts: postArray,
168→        starPulls,
169→        centroidByUser,
170→        activeSectorKeys,
171→        activePostIds,
172→        sectorSize: SECTOR_SIZE,
173→    });
174→
175→    // ── Render galaxies = hash galaxies with animated positions ──────
176→    const galaxies = useMemo(() => {
177→        return hashGalaxies.map(g => {
178→            const animated = galaxyPositions.get(g.userId);
179→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
180→        });
181→    }, [hashGalaxies, galaxyPositions]);
182→
183→    // Home position for distance tracker — same resolution as auto-focus.
184→    const homePosition = useMemo(() => {
185→        if (!userId) return { x: 0, y: 0 };
186→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
187→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
188→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
189→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
190→
191→    const getComputedStarPosition = useCallback((post) => {
192→        if (!post) return null;
193→
194→        const uid = post.users?.id ?? post.user_id;
195→        const hashGal = userHomeCoords(uid);
196→        const animGal = galaxyPositions.get(uid);
197→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
198→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
199→        const pull = starPullOffsets.get(post.id);
200→
201→        const baseX = post.universe_x ?? post.display_x;
202→        const baseY = post.universe_y ?? post.display_y;
203→        if (baseX == null || baseY == null) return null;
204→
205→        return {
206→            x: baseX + galDx + (pull?.dx ?? 0),
207→            y: baseY + galDy + (pull?.dy ?? 0),
208→        };
209→    }, [galaxyPositions, starPullOffsets]);
210→
211→    // ── Hoisted computedStarPositions for sharing across layers ──────
212→    const computedStarPositions = useMemo(() => {
213→        const map = new Map();
214→        for (const post of postArray) {
215→            const uid = post.users?.id ?? post.user_id;
216→            const hashGal = userHomeCoords(uid);
217→            const animGal = galaxyPositions.get(uid);
218→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
219→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
220→            const pull = starPullOffsets.get(post.id);
221→
222→            const baseX = post.universe_x ?? post.display_x;
223→            const baseY = post.universe_y ?? post.display_y;
224→            if (baseX == null || baseY == null) continue;
225→
226→            let x = baseX + galDx + (pull?.dx ?? 0);
227→            let y = baseY + galDy + (pull?.dy ?? 0);
228→
229→            map.set(post.id, { x, y });
230→        }
231→        return map;
232→    }, [postArray, galaxyPositions, starPullOffsets]);
233→
234→    // ── Constellation pull offsets (spring constraint) ─────────────
235→    const acceptedConstellations = useMemo(
236→        () => constellations.filter(c => c.status === 'accepted'),
237→        [constellations]
238→    );
239→
240→    const constellationPullOffsets = useMemo(
241→        () => computeConstellationPullOffsets(acceptedConstellations, computedStarPositions),
242→        [acceptedConstellations, computedStarPositions]
243→    );
244→
245→    // ── Final star positions with constellation pull applied ───────
246→    const finalStarPositions = useMemo(() => {
247→        if (constellationPullOffsets.size === 0) return computedStarPositions;
248→
249→        const map = new Map(computedStarPositions);
250→        for (const [postId, offset] of constellationPullOffsets) {
251→            const pos = map.get(postId);
252→            if (pos) {
253→                map.set(postId, {
254→                    x: pos.x + offset.dx,
255→                    y: pos.y + offset.dy,
256→                });
257→            }
258→        }
259→        return map;
260→    }, [computedStarPositions, constellationPullOffsets]);
261→
262→    // ── Constellation chain colors ────────────────────────────────
263→    const chainColors = useMemo(() => {
264→        const chains = computeConstellationChains(acceptedConstellations);
265→        return assignChainColors(chains);
266→    }, [acceptedConstellations]);
267→
268→    // Resolve logged-in user's galaxy target independently from viewport data.
269→    useEffect(() => {
270→        if (!userId) return;
271→        if (ownGalaxyLookupStartedRef.current) return;
272→
273→        ownGalaxyLookupStartedRef.current = true;
274→        let cancelled = false;
275→
276→        const resolveOwnGalaxyTarget = async () => {
277→            try {
278→                const { data, error } = await supabase
279→                    .from('galaxy_centroids')
280→                    .select('galaxy_x, galaxy_y')
281→                    .eq('user_id', userId)
282→                    .maybeSingle();
283→
284→                if (cancelled) return;
285→
286→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
287→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
288→                    setHasOwnPosts(true);
289→                    return;
290→                }
291→            } catch (err) {
292→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
293→            }
294→
295→            if (!cancelled) {
296→                setOwnGalaxyTarget(userHomeCoords(userId));
297→            }
298→        };
299→
300→        resolveOwnGalaxyTarget();
301→
302→        return () => {
303→            cancelled = true;
304→        };
305→    }, [userId]);
306→
307→    // One-time wormhole fetch on mount
308→    useEffect(() => {
309→        let cancelled = false;
310→
311→        const fetchWormholes = async () => {
312→            try {
313→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
314→                    similarity_threshold: 0.7,
315→                    min_distance: 0,
316→                    max_pairs: 30,
317→                });
318→                if (cancelled) return;
319→                if (error) {
320→                    console.warn('[universe] wormhole fetch error:', error.message);
321→                    return;
322→                }
323→                console.log('[universe] wormhole pairs:', data);
324→                if (Array.isArray(data) && data.length > 0) {
325→                    setWormholes(data);
326→                }
327→            } catch (err) {
328→                if (!cancelled) {
329→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
330→                }
331→            }
332→        };
333→
334→        fetchWormholes();
335→        return () => { cancelled = true; };
336→    }, []);
337→
338→    // Debounced fetch on camera/zoom change
339→    useEffect(() => {
340→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
341→
342→        fetchDebounceRef.current = setTimeout(async () => {
343→            const bounds = getViewportBounds();
344→            try {
345→                const result = await getUniversePosts(
346→                    bounds.minX,
347→                    bounds.maxX,
348→                    bounds.minY,
349→                    bounds.maxY,
350→                    200
351→                );
352→                if (result?.data) {
353→                    setPosts(prev => {
354→                        const next = new Map(prev);
355→                        for (const post of result.data) {
356→                            next.set(post.id, post);
357→                        }
358→                        return next;
359→                    });
360→                    if (userId && hasOwnPosts !== true) {
361→                        const ownsAny = result.data.some(p =>
362→                            (p.users?.id ?? p.user_id) === userId
363→                        );
364→                        if (ownsAny) setHasOwnPosts(true);
365→                    }
366→                }
367→                // Keep server gravity data as fallback when embeddings are absent in payload.
368→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
369→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
370→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
371→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
372→
373→                // Fetch constellations for visible posts
374→                if (result?.data?.length > 0) {
375→                    const visibleIds = result.data.map(p => p.id);
376→                    try {
377→                        const constResult = await getViewportConstellations(visibleIds);
378→                        if (constResult?.data) {
379→                            setConstellations(constResult.data);
380→                        }
381→                    } catch (constErr) {
382→                        console.warn('[universe] constellation fetch failed:', constErr?.message || constErr);
383→                    }
384→                }
385→            } catch (err) {
386→                console.error('Failed to fetch universe posts:', err);
387→            } finally {
388→                if (!initialFetchResolvedRef.current) {
389→                    initialFetchResolvedRef.current = true;
390→                    setIsInitialLoading(false);
391→                }
392→            }
393→        }, 400);
394→
395→        return () => {
396→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
397→        };
398→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
399→
400→    const handleStarClick = useCallback(async (post) => {
401→        if (isFlying.current) return;
402→
403→        // Intercept for link mode
404→        if (isLinkMode) {
405→            setLinkModeError(null);
406→            const result = await handleStarClickInLinkMode(post);
407→            if (result?.error) {
408→                setLinkModeError(result.error);
409→                setTimeout(() => setLinkModeError(null), 3000);
410→            }
411→            return;
412→        }
413→
414→        setSelectedPost(post);
415→        setSelectedGalaxy(null);
416→        setGalaxyProfile(null);
417→
418→        const position = getComputedStarPosition(post);
419→        if (!position) return;
420→
421→        flyTo(position.x, position.y, 1.2, () => {
422→            setPulsingId(post.id);
423→            setTimeout(() => setPulsingId(null), 700);
424→        });
425→    }, [flyTo, getComputedStarPosition, isFlying, isLinkMode, handleStarClickInLinkMode]);
426→
427→    const handleGalaxyClick = useCallback(async (galaxy) => {
428→        if (isFlying.current) return;
429→        setSelectedGalaxy(galaxy);
430→        setSelectedPost(null);
431→        setGalaxyProfile(null);
432→        flyTo(galaxy.x, galaxy.y, 0.8);
433→
434→        try {
435→            const data = await getUserData(galaxy.userId);
436→            const profile = data?.userData?.[0] || null;
437→            setGalaxyProfile(profile);
438→        } catch (err) {
439→            console.error('Failed to fetch galaxy profile:', err);
440→        }
441→    }, [flyTo, isFlying]);
442→
443→    const handleReadPost = useCallback(() => {
444→        if (!selectedPost) return;
445→        navigate(`/home/post/${selectedPost.id}`);
446→    }, [selectedPost, navigate]);
447→
448→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
449→        if (mode === 'drag') {
450→            jumpTo(worldX, worldY);
451→            return;
452→        }
453→        flyTo(worldX, worldY, zoom);
454→    }, [flyTo, jumpTo, zoom]);
455→
456→    // Enrich wormhole positions with live gravity-computed post coords
457→    const enrichedWormholes = useMemo(() => {
458→        return wormholes.map(wh => {
459→            const postA = posts.get(wh.post_a);
460→            const postB = posts.get(wh.post_b);
461→            const posA = postA ? getComputedStarPosition(postA) : null;
462→            const posB = postB ? getComputedStarPosition(postB) : null;
463→            return {
464→                ...wh,
465→                a_x: posA?.x ?? wh.a_x,
466→                a_y: posA?.y ?? wh.a_y,
467→                b_x: posB?.x ?? wh.b_x,
468→                b_y: posB?.y ?? wh.b_y,
469→            };
470→        });
471→    }, [wormholes, posts, getComputedStarPosition]);
472→
473→    // Find wormhole connection for a given post (if any)
474→    const getWormholeForPost = useCallback((postId) => {
475→        if (!postId || enrichedWormholes.length === 0) return null;
476→        for (const wh of enrichedWormholes) {
477→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
478→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
479→        }
480→        return null;
481→    }, [enrichedWormholes]);
482→
483→    const handleWormholeTravel = useCallback(() => {
484→        if (!selectedPost || isFlying.current) return;
485→        const match = getWormholeForPost(selectedPost.id);
486→        if (!match) return;
487→        const { wormhole, side } = match;
488→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
489→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
490→        setSelectedPost(null);
491→        setIsWarping(true);
492→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
493→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
494→
495→    // One-time auto focus after first payload is loaded.
496→    // Skip if we have a constellation flyTo target — that effect handles it instead.
497→    useEffect(() => {
498→        if (!userId) return;
499→        if (isInitialLoading) return;
500→        if (hasAutoFocusedOwnGalaxyRef.current) return;
501→        if (constellationFlyToRef.current) return;
502→
503→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
504→        const target = ownGalaxy
505→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
506→            : (centroidTargets.get(userId) || ownGalaxyTarget);
507→
508→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
509→        if (!target) return;
510→
511→        hasAutoFocusedOwnGalaxyRef.current = true;
512→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
513→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
514→
515→    // Fly to constellation midpoint when arriving from a notification link.
516→    useEffect(() => {
517→        const target = constellationFlyToRef.current;
518→        if (!target) return;
519→        if (isInitialLoading) return;
520→
521→        const posA = finalStarPositions.get(target.starIdA);
522→        const posB = finalStarPositions.get(target.starIdB);
523→        if (!posA || !posB) return;
524→
525→        constellationFlyToRef.current = null;
526→        hasAutoFocusedOwnGalaxyRef.current = true;
527→
528→        const mx = (posA.x + posB.x) / 2;
529→        const my = (posA.y + posB.y) / 2;
530→        flyTo(mx, my, 1.0);
531→
532→        // Clear navigation state so refreshing doesn't re-trigger
533→        navigate(location.pathname, { replace: true, state: {} });
534→    }, [isInitialLoading, finalStarPositions, flyTo, navigate, location.pathname]);
535→
536→    const settledPayload = useMemo(() => {
537→        if (!isSettled || activePosts.length === 0) return [];
538→
539→        const payload = [];
540→        for (const post of activePosts) {
541→            if (!post?.id) continue;
542→            const pos = getComputedStarPosition(post);
543→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
544→
545→            payload.push({
546→                post_id: post.id,
547→                settled_x: Math.round(pos.x * 100) / 100,
548→                settled_y: Math.round(pos.y * 100) / 100,
549→            });
550→        }
551→
552→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
553→        return payload;
554→    }, [activePosts, getComputedStarPosition, isSettled]);
555→
556→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
557→    useEffect(() => {
558→        if (!ENABLE_SETTLED_RPC_SAVE) return;
559→        if (!isSettled || settledPayload.length === 0) return;
560→
561→        const signature = JSON.stringify(settledPayload);
562→        if (signature === lastSettledPayloadRef.current) return;
563→
564→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
565→        settleDebounceRef.current = setTimeout(async () => {
566→            lastSettledPayloadRef.current = signature;
567→            try {
568→                const { error } = await supabase.rpc('save_universe_settled_positions', {
569→                    positions_payload: settledPayload,
570→                });
571→                if (error) {
572→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
573→                }
574→            } catch (err) {
575→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
576→            }
577→        }, 1200);
578→
579→        return () => {
580→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
581→        };
582→    }, [isSettled, settledPayload]);
583→
584→    // ESC key to cancel link mode
585→    useEffect(() => {
586→        if (!isLinkMode) return;
587→        const handleKeyDown = (e) => {
588→            if (e.key === 'Escape') cancelLinkMode();
589→        };
590→        window.addEventListener('keydown', handleKeyDown);
591→        return () => window.removeEventListener('keydown', handleKeyDown);
592→    }, [isLinkMode, cancelLinkMode]);
593→
594→    useEffect(() => {
595→        return () => {
596→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
597→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
598→        };
599→    }, []);
600→
601→    return (
602→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
603→            <button className={styles.backButton} onClick={() => navigate('/home')}>
604→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
605→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
606→                </svg>
607→                Back
608→            </button>
609→
610→            {userId && (
611→                <button
612→                    className={`${styles.linkModeButton} ${isLinkMode ? styles.linkModeActive : ''}`}
613→                    onClick={toggleLinkMode}
614→                    disabled={isSubmitting}
615→                >
616→                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
617→                        <path d="M3.9 12c0-1.71 1.39-3.1 3.1-3.1h4V7H7c-2.76 0-5 2.24-5 5s2.24 5 5 5h4v-1.9H7c-1.71 0-3.1-1.39-3.1-3.1zM8 13h8v-2H8v2zm9-6h-4v1.9h4c1.71 0 3.1 1.39 3.1 3.1s-1.39 3.1-3.1 3.1h-4V17h4c2.76 0 5-2.24 5-5s-2.24-5-5-5z"/>
618→                    </svg>
619→                    {isLinkMode
620→                        ? (firstStar ? 'Select second star...' : 'Select your star...')
621→                        : 'Link Stars'}
622→                </button>
623→            )}
624→
625→            {isLinkMode && (
626→                <div className={styles.linkModeIndicator}>
627→                    <span>
628→                        {linkModeError
629→                            ? linkModeError
630→                            : firstStar
631→                                ? `Selected "${firstStar.title}" — now click another user's star`
632→                                : 'Click one of your stars to begin'}
633→                    </span>
