643→                    return dist < 50
644→                        ? 'Home'
645→                        : `${dist.toLocaleString()} Lightyears from Home`;
646→                })()}
647→            </div>
648→
649→            {isInitialLoading && (
650→                <div className={styles.loadingOverlay}>
651→                    <div className={styles.loadingCard}>
652→                        <div className={styles.loadingSpinner} />
653→                        <div className={styles.loadingText}>Loading universe...</div>
654→                    </div>
655→                </div>
656→            )}
657→
658→            <Stage
659→                ref={stageRef}
660→                width={stageSize.width}
661→                height={stageSize.height}
662→                {...stageEvents}
663→            >
664→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
665→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
666→                <NebulaLayer
667→                    layerProps={getLayerProps(0.85)}
668→                    galaxies={galaxies}
669→                    centroids={centroids}
