679→                    <ConstellationLayer
680→                        layerProps={getLayerProps(1.0)}
681→                        constellations={constellations}
682→                        computedStarPositions={finalStarPositions}
683→                        zoom={zoom}
684→                        chainColors={chainColors}
685→                        userId={userId}
686→                    />
687→                )}
688→                <InteractiveLayer
689→                    layerProps={getLayerProps(1.0)}
690→                    posts={postArray}
691→                    galaxies={galaxies}
692→                    zoom={zoom}
693→                    showTitles={showTitles}
694→                    pulsingId={pulsingId}
695→                    onStarClick={handleStarClick}
696→                    onGalaxyClick={handleGalaxyClick}
697→                    galaxyPositions={galaxyPositions}
698→                    starPullOffsets={starPullOffsets}
699→                    similarPairs={similarPairs}
700→                    galaxyEdges={effectiveGalaxyEdges}
701→                    activePostIds={activePostIds}
702→                    useEmbeddingBridges={hasEmbeddingGravity}
