714→                zoom={zoom}
715→                stageSize={stageSize}
716→                onNavigate={handleMinimapNavigate}
717→                constellations={acceptedConstellations}
718→                computedStarPositions={finalStarPositions}
719→            />
720→
721→            {selectedGalaxy && galaxyProfile && (
722→                <div className={styles.galaxyPreviewPanel}>
