724→                        className={styles.galaxyPreviewClose}
725→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
726→                    >
727→                        &times;
728→                    </button>
729→                    <div
730→                        className={styles.galaxyPreviewBg}
731→                        style={galaxyProfile.background || {}}
732→                    />
733→                    <div className={styles.galaxyPreviewContent}>
734→                        <img
735→                            className={styles.galaxyPreviewAvatar}
736→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
737→                            alt=""
738→                        />
739→                        <div className={styles.galaxyPreviewHeading}>
740→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
741→                        </div>
742→                        {galaxyProfile.bio && (
743→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
744→                        )}
745→                        <button
746→                            className={styles.galaxyPreviewVisitBtn}
747→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
748→                        >
749→                            Visit Profile
750→                        </button>
751→                    </div>
752→                </div>
753→            )}
754→
755→            {selectedPost && (
756→                <div className={styles.previewPanel}>
757→                    <button
758→                        className={styles.previewClose}
759→                        onClick={() => setSelectedPost(null)}
760→                    >
761→                        &times;
762→                    </button>
763→                    <div className={styles.previewAuthor}>
764→                        <img
765→                            className={styles.previewAvatar}
766→                            src={selectedPost.users?.image_url || selectedPost.user_image_url || '/assets/profile.jpg'}
767→                            alt=""
768→                        />
769→                        <span className={styles.previewAuthorName}>
770→                            {selectedPost.users?.name || selectedPost.user_name || 'Anonymous'}
771→                        </span>
772→                    </div>
773→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
774→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
775→                    <div className={styles.previewLikes}>
776→                        {(() => {
777→                            const count = selectedPost.like_count != null
778→                                ? selectedPost.like_count
779→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
780→                                    ? selectedPost.likes[0].count : 0);
781→                            return `${count} like${count !== 1 ? 's' : ''}`;
782→                        })()}
783→                    </div>
784→                    <div className={styles.previewActions}>
785→                        <button className={styles.previewReadBtn} onClick={handleReadPost}>
786→                            Read
787→                        </button>
788→                        {getWormholeForPost(selectedPost.id) && (
789→                            <div className={styles.wormholeBtnWrap}>
790→                                <button className={styles.wormholeBtn} onClick={handleWormholeTravel}>
791→                                    Wormhole to "{getWormholeForPost(selectedPost.id).targetTitle}"
792→                                </button>
793→                                <div className={styles.wormholeTooltip}>
794→                                    This post is semantically linked to a distant post. Click to warp there instantly.
795→                                </div>
796→                            </div>
797→                        )}
798→                    </div>
799→                </div>
800→            )}
801→        </div>
802→    );
803→};
804→
805→export default Universe;
