  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Line, Text } from 'react-konva';
  3→import { STAR_COLORS } from '../utils/starUtils';
  4→
  5→const parseHex = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→const ConstellationLayer = React.memo(({ layerProps, constellations, computedStarPositions, zoom, chainColors, userId }) => {
 12→    const lineRefsMap = useRef(new Map());
 13→    const rafRef = useRef(null);
 14→
 15→    const linkData = useMemo(() => {
 16→        if (!Array.isArray(constellations) || constellations.length === 0) return [];
 17→        return constellations.map((link, i) => {
 18→            const colorHex = chainColors?.get(link.id) || STAR_COLORS[i % STAR_COLORS.length];
 19→            const rgb = parseHex(colorHex);
 20→            const isPending = link.status === 'pending';
 21→            const isDeclined = link.status === 'declined';
 22→            const isOwnPending = isPending && (link.user_id_a === userId || link.user_id_b === userId);
 23→            return { ...link, rgb, colorHex, isPending, isDeclined, isOwnPending };
 24→        });
 25→    }, [constellations, chainColors, userId]);
 26→
 27→    const animate = useCallback(() => {
 28→        const offset = -performance.now() * 0.06;
 29→        let layer = null;
 30→        lineRefsMap.current.forEach((node) => {
 31→            if (node) {
 32→                node.dashOffset(offset);
 33→                if (!layer) layer = node.getLayer();
 34→            }
 35→        });
 36→        if (layer) layer.batchDraw();
 37→        rafRef.current = requestAnimationFrame(animate);
 38→    }, []);
 39→
 40→    useEffect(() => {
 41→        const hasAccepted = linkData.some((l) => !l.isPending);
 42→        if (!hasAccepted) return;
 43→        rafRef.current = requestAnimationFrame(animate);
 44→        return () => {
 45→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
 46→        };
 47→    }, [animate, linkData]);
 48→
 49→    // Clean up stale refs
 50→    useEffect(() => {
 51→        const activeIds = new Set(linkData.map((l) => l.id));
 52→        lineRefsMap.current.forEach((_, key) => {
 53→            if (!activeIds.has(key)) lineRefsMap.current.delete(key);
 54→        });
 55→    }, [linkData]);
 56→
 57→    if (linkData.length === 0) return null;
 58→
 59→    return (
 60→        <Layer {...layerProps} listening={false}>
 61→            {linkData.map((link) => {
 62→                if (link.isDeclined) return null;
 63→
 64→                const posA = computedStarPositions.get(link.star_id_a)
 65→                    || (link.a_universe_x != null ? { x: link.a_universe_x, y: link.a_universe_y } : null);
 66→                const posB = computedStarPositions.get(link.star_id_b)
 67→                    || (link.b_universe_x != null ? { x: link.b_universe_x, y: link.b_universe_y } : null);
 68→                if (!posA || !posB) return null;
 69→
 70→                const ax = posA.x, ay = posA.y;
 71→                const bx = posB.x, by = posB.y;
 72→                const { rgb } = link;
 73→
 74→                if (link.isPending) {
 75→                    if (!link.isOwnPending) return null;
 76→                    return (
 77→                        <Line
 78→                            key={`pending-${link.id}`}
 79→                            points={[ax, ay, bx, by]}
 80→                            dash={[6, 10]}
 81→                            stroke={`rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`}
 82→                            strokeWidth={1}
 83→                            lineCap="round"
 84→                            listening={false}
 85→                            perfectDrawEnabled={false}
 86→                        />
 87→                    );
 88→                }
 89→
 90→                const mx = (ax + bx) / 2;
 91→                const my = (ay + by) / 2;
 92→
 93→                return (
 94→                    <React.Fragment key={`constellation-${link.id}`}>
 95→                        {/* Outer glow */}
 96→                        <Line
 97→                            points={[ax, ay, bx, by]}
 98→                            dash={[12, 8]}
 99→                            stroke={`rgba(${rgb.r},${rgb.g},${rgb.b},0.1)`}
100→                            strokeWidth={5}
101→                            opacity={1}
102→                            lineCap="round"
103→                            listening={false}
104→                            perfectDrawEnabled={false}
105→                        />
106→                        {/* Inner energy line — animated dashOffset */}
107→                        <Line
108→                            ref={(node) => {
109→                                if (node) lineRefsMap.current.set(link.id, node);
110→                                else lineRefsMap.current.delete(link.id);
111→                            }}
112→                            points={[ax, ay, bx, by]}
113→                            dash={[12, 8]}
114→                            stroke={`rgba(${rgb.r},${rgb.g},${rgb.b},0.4)`}
