 87→            postArray,
 88→            (post) => ({
 89→                x: post?.display_x ?? post?.universe_x,
 90→                y: post?.display_y ?? post?.universe_y,
 91→            }),
 92→            SECTOR_SIZE
 93→        )
 94→    ), [postArray]);
