101→    const activeSectorKeys = useMemo(
102→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
103→        [centerSectorKey]
104→    );
105→
106→    const activePosts = useMemo(() => {
107→        if (activeSectorKeys.size === 0) return postArray;
108→
109→        const next = [];
110→        for (const key of activeSectorKeys) {
111→            const bucket = postSectorIndex.get(key);
112→            if (bucket?.length) next.push(...bucket);
113→        }
114→        return next;
115→    }, [postArray, postSectorIndex, activeSectorKeys]);
