130→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
131→    const hashGalaxies = useMemo(() => {
132→        const seen = new Map();
133→        for (const post of postArray) {
134→            const uid = post.users?.id ?? post.user_id;
