147→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
148→    const centroidTargets = useMemo(() => {
149→        const map = new Map();
150→        for (const c of centroids) {
151→            if (c.galaxy_x != null && c.galaxy_y != null) {
