317→                    min_distance: 0,
318→                    max_pairs: 30,
319→                });
320→                if (cancelled) return;
321→                if (error) {
322→                    console.warn('[universe] wormhole fetch error:', error.message);
323→                    return;
324→                }
325→                console.log('[universe] wormhole pairs:', data);
326→                if (Array.isArray(data) && data.length > 0) {
327→                    setWormholes(data);
