200→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
201→        const pull = starPullOffsets.get(post.id);
202→
203→        const baseX = post.universe_x ?? post.display_x;
204→        const baseY = post.universe_y ?? post.display_y;
205→        if (baseX == null || baseY == null) return null;
206→
207→        return {
208→            x: baseX + galDx + (pull?.dx ?? 0),
209→            y: baseY + galDy + (pull?.dy ?? 0),
210→        };
211→    }, [galaxyPositions, starPullOffsets]);
