220→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
221→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
222→            const pull = starPullOffsets.get(post.id);
223→
224→            const baseX = post.universe_x ?? post.display_x;
225→            const baseY = post.universe_y ?? post.display_y;
226→            if (baseX == null || baseY == null) continue;
227→
228→            let x = baseX + galDx + (pull?.dx ?? 0);
229→            let y = baseY + galDy + (pull?.dy ?? 0);
230→
231→            map.set(post.id, { x, y });
232→        }
233→        return map;
234→    }, [postArray, galaxyPositions, starPullOffsets]);
